"use client";

import { useSearchParams } from "next/navigation";
import { Suspense } from "react";
import {
	ResizablePanelGroup,
	ResizablePanel,
	ResizableHandle,
} from "@/components/ui/resizable";
import { AssetsPanel } from "@/components/editor/panels/assets";
import { PropertiesPanel } from "@/components/editor/panels/properties";
import { Timeline } from "@/timeline/components";
import { PreviewPanel } from "@/preview/components";
import { EditorHeader } from "@/components/editor/editor-header";
import { EditorProvider } from "@/components/providers/editor-provider";
import { Onboarding } from "@/components/editor/onboarding";
import { MigrationDialog } from "@/project/components/migration-dialog";
import { usePanelStore } from "@/editor/panel-store";
import { usePasteMedia } from "@/media/use-paste-media";
import { MobileGate } from "@/components/editor/mobile-gate";
import { useMemo, useState } from "react";
import { useEditor } from "@/editor/use-editor";
import { Cancel01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { Button } from "@/components/ui/button";
import { ChangelogNotification } from "@/changelog/components/changelog-notification";
import {
	createPreviewOverlayControl,
	isPreviewOverlayVisible,
	mergePreviewOverlaySources,
} from "@/preview/overlays";
import { usePreviewStore } from "@/preview/preview-store";
import { getGuidePreviewOverlaySource } from "@/guides";
import {
	bookmarkNotesPreviewOverlay,
	getBookmarkPreviewOverlaySource,
} from "@/timeline/bookmarks/index";

function Editor() {
	const searchParams = useSearchParams();
	const projectId = searchParams.get("id") || "local" as string;

	return (
		<MobileGate>
			<EditorProvider projectId={projectId}>
				<div className="bg-background flex h-screen w-screen flex-col overflow-hidden">
					<DegradedRendererBanner />
					<EditorHeader />
					<div className="min-h-0 min-w-0 flex-1">
						<EditorLayout />
					</div>
					<Onboarding />
					<MigrationDialog />
					<ChangelogNotification />
				</div>
			</EditorProvider>
		</MobileGate>
	);
}

function DegradedRendererBanner() {
	const isDegraded = useEditor((e) => e.renderer.isDegraded);
	const [dismissed, setDismissed] = useState(false);
	if (!isDegraded || dismissed) return null;

	return (
		<div className="bg-accent border-b h-9 flex items-center justify-center gap-2 text-xs text-muted-foreground">
			<span>For the best experience, open MajanCut Pro in Chrome.</span>
			<Button
				variant="text"
				size="icon"
				className="p-0 w-auto [&_svg]:size-3.5"
				onClick={() => setDismissed(true)}
				aria-label="Dismiss"
			>
				<HugeiconsIcon icon={Cancel01Icon} />
			</Button>
		</div>
	);
}

function EditorLayout() {
	usePasteMedia();
	const { panels, setPanel } = usePanelStore();
	const activeScene = useEditor((editor) =>
		editor.scenes.getActiveSceneOrNull(),
	);
	const currentTime = useEditor((editor) => editor.playback.getCurrentTime());
	const activeGuide = usePreviewStore((state) => state.activeGuide);
	const overlays = usePreviewStore((state) => state.overlays);
	const setOverlayVisibility = usePreviewStore(
		(state) => state.setOverlayVisibility,
	);
	const showBookmarkNotes = isPreviewOverlayVisible({
		overlay: bookmarkNotesPreviewOverlay,
		overlays,
	});

	const overlaySource = useMemo(
		() =>
			mergePreviewOverlaySources({
				sources: [
					getGuidePreviewOverlaySource({
						guideId: activeGuide,
					}),
					activeScene
						? getBookmarkPreviewOverlaySource({
								bookmarks: activeScene.bookmarks,
								time: currentTime,
								isVisible: showBookmarkNotes,
							})
						: {
								definitions: [bookmarkNotesPreviewOverlay],
								instances: [],
							},
				],
			}),
		[activeGuide, activeScene, currentTime, showBookmarkNotes],
	);

	const overlayControls = useMemo(
		() =>
			overlaySource.definitions.map((overlay) =>
				createPreviewOverlayControl({ overlay, overlays }),
			),
		[overlaySource.definitions, overlays],
	);

	return (
		<ResizablePanelGroup
			direction="vertical"
			className="size-full gap-[0.18rem]"
			onLayout={(sizes) => {
				setPanel({
					panel: "mainContent",
					size: sizes[0] ?? panels.mainContent,
				});
				setPanel({
					panel: "timeline",
					size: sizes[1] ?? panels.timeline,
				});
			}}
		>
			<ResizablePanel
				defaultSize={panels.mainContent}
				minSize={30}
				maxSize={85}
				className="min-h-0"
			>
				<ResizablePanelGroup
					direction="horizontal"
					className="size-full gap-[0.19rem] px-3"
					onLayout={(sizes) => {
						setPanel({ panel: "tools", size: sizes[0] ?? panels.tools });
						setPanel({ panel: "preview", size: sizes[1] ?? panels.preview });
						setPanel({
							panel: "properties",
							size: sizes[2] ?? panels.properties,
						});
					}}
				>
					<ResizablePanel
						defaultSize={panels.tools}
						minSize={15}
						maxSize={40}
						className="min-w-0"
					>
						<AssetsPanel />
					</ResizablePanel>

					<ResizableHandle withHandle />

					<ResizablePanel
						defaultSize={panels.preview}
						minSize={30}
						className="min-h-0 min-w-0 flex-1"
					>
						<PreviewPanel
							overlayControls={overlayControls}
							overlayInstances={overlaySource.instances}
							onOverlayVisibilityChange={setOverlayVisibility}
						/>
					</ResizablePanel>

					<ResizableHandle withHandle />

					<ResizablePanel
						defaultSize={panels.properties}
						minSize={15}
						maxSize={40}
						className="min-w-0"
					>
						<PropertiesPanel />
					</ResizablePanel>
				</ResizablePanelGroup>
			</ResizablePanel>

			<ResizableHandle withHandle />

			<ResizablePanel
				defaultSize={panels.timeline}
				minSize={15}
				maxSize={70}
				className="min-h-0 px-3 pb-3"
			>
				<Timeline />
			</ResizablePanel>
		</ResizablePanelGroup>
	);
}


function WebGPUGate({ children }: { children: React.ReactNode }) {
	const React = require("react") as typeof import("react");
	const [state, setState] = React.useState<null | "ok" | "no">(null);
	const [bootErr, setBootErr] = React.useState<string>("");
	React.useEffect(() => {
		// يكفي WebGPU أو WebGL2 — المحرك يتبدل تلقائياً بينهما
		const hasWebGPU = typeof navigator !== "undefined" && "gpu" in navigator;
		let hasWebGL2 = false;
		try {
			const c = document.createElement("canvas");
			hasWebGL2 = !!c.getContext("webgl2");
		} catch (e) {}
		setState(hasWebGPU || hasWebGL2 ? "ok" : "no");
		// عارض أخطاء مرئي — الموبايل ملوش كونسول
		const onErr = (e: ErrorEvent) => setBootErr((p) => p || String(e.message || e.error || "خطأ غير معروف"));
		// التقاط رسالة panic الحقيقية من محرك Rust (بتتطبع في console.error)
		const origErr = console.error.bind(console);
		console.error = (...args: unknown[]) => {
			try {
				const msg = args.map((a) => (a instanceof Error ? a.message : String(a))).join(" ");
				if (/panicked|wasm|unreachable|WebGL|WebGPU|format|texture|adapter|device/i.test(msg)) {
					setBootErr((p) => (p && p.includes("panicked") ? p : msg.slice(0, 700)));
				}
			} catch (e) {}
			origErr(...args);
		};
		const onRej = (e: PromiseRejectionEvent) => setBootErr(String((e.reason && (e.reason.message || e.reason)) || "promise rejection"));
		window.addEventListener("error", onErr);
		window.addEventListener("unhandledrejection", onRej);
		return () => { window.removeEventListener("error", onErr); window.removeEventListener("unhandledrejection", onRej); };
	}, []);
	if (state === null) return null;
	if (state === "no") {
		return (
			<div dir="rtl" style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:24,textAlign:"center",background:"#0b0b0e",color:"#eee"}}>
				<div style={{maxWidth:480}}>
					<div style={{fontSize:44,marginBottom:12}}>🎬</div>
					<h2 style={{fontSize:20,marginBottom:10}}>متصفحك قديم جداً على محرك الرسوميات</h2>
					<p style={{lineHeight:1.9,color:"#bbb",fontSize:14}}>حدّث المتصفح أو النظام، أو استخدم النسخة الخفيفة:{" "}
						<a href="https://ahmd753.github.io/majancut/" style={{color:"#e8b23a",fontWeight:700}}>ماجان‌كَت</a>
					</p>
				</div>
			</div>
		);
	}
	return (
		<>
			{bootErr ? (
				<div dir="ltr" style={{position:"fixed",top:0,left:0,right:0,zIndex:9999,background:"#7a1f1f",color:"#fff",padding:"8px 12px",fontSize:12,fontFamily:"monospace",whiteSpace:"pre-wrap"}}>
					⚠️ {bootErr.slice(0,500)}
				</div>
			) : null}
			{children}
		</>
	);
}

export default function EditorPageWrapper(){
	return (<WebGPUGate><Suspense fallback={null}><Editor /></Suspense></WebGPUGate>);
}
